{
  "claimant": "buyer_agent",
  "respondent": "seller_agent",
  "contract": {
    "parties": ["buyer_agent", "seller_agent"],
    "obligations": ["Deliver logo design by June 20"],
    "deadlines": ["2026-06-20"],
    "deliverables": ["3 logo concepts"],
    "payment_terms": "10 USDC on delivery"
  },
  "claim": "Deliverable was never received.",
  "desired_remedy": "full_refund",
  "policy": "freelance-delivery",
  "evidence": [
    {
      "type": "contract",
      "source": "agreement.json",
      "timestamp": "2026-06-15",
      "claimed_fact": "Seller must deliver 3 logo concepts by June 20"
    },
    {
      "type": "payment_proof",
      "source": "x402_receipt",
      "timestamp": "2026-06-15",
      "claimed_fact": "Buyer paid 10 USDC upfront"
    },
    {
      "type": "log",
      "source": "design_tool",
      "timestamp": "2026-06-22",
      "claimed_fact": "No design files exported or delivered"
    }
  ]
}

{
  "claimant": "developer_agent",
  "respondent": "client_agent",
  "contract": {
    "parties": ["developer_agent", "client_agent"],
    "obligations": ["Complete API integration milestone"],
    "deadlines": ["2026-06-18"],
    "deliverables": ["Working API"],
    "payment_terms": "25 USDC within 7 days of completion"
  },
  "claim": "Milestone completed but payment never received.",
  "desired_remedy": "payment",
  "policy": "milestone-payment",
  "evidence": [
    {
      "type": "contract",
      "source": "milestone_agreement.json",
      "timestamp": "2026-06-10",
      "claimed_fact": "25 USDC due on milestone completion within 7 days"
    },
    {
      "type": "commit",
      "source": "github",
      "timestamp": "2026-06-17",
      "claimed_fact": "API endpoint implemented and deployed"
    },
    {
      "type": "message",
      "source": "slack",
      "timestamp": "2026-06-18",
      "claimed_fact": "Buyer acknowledged milestone completion"
    },
    {
      "type": "log",
      "source": "payment_ledger",
      "timestamp": "2026-06-22",
      "claimed_fact": "No payment received 4 days after completion"
    }
  ]
}

{
  "claimant": "researcher_agent",
  "respondent": "vendor_agent",
  "contract": {
    "parties": ["researcher_agent", "vendor_agent"],
    "obligations": ["Pay for reproducible critical bugs"],
    "deliverables": ["Bug report"],
    "payment_terms": "50 USDC for critical severity"
  },
  "claim": "Critical bug rejected but it is reproducible.",
  "desired_remedy": "payment",
  "policy": "bug-bounty",
  "evidence": [
    {
      "type": "contract",
      "source": "bounty_program.json",
      "timestamp": "2026-06-01",
      "claimed_fact": "50 USDC for critical bugs"
    },
    {
      "type": "file",
      "source": "bug_report.md",
      "timestamp": "2026-06-19",
      "claimed_fact": "Detailed reproduction steps for critical vulnerability"
    },
    {
      "type": "log",
      "source": "test_env",
      "timestamp": "2026-06-20",
      "claimed_fact": "Bug reproduced in 3 independent runs confirming critical severity"
    },
    {
      "type": "message",
      "source": "email",
      "timestamp": "2026-06-21",
      "claimed_fact": "Vendor claimed non-reproducible without testing"
    }
  ]
}

{
  "claimant": "consumer_agent",
  "respondent": "provider_agent",
  "contract": {
    "parties": ["consumer_agent", "provider_agent"],
    "obligations": ["Maintain 99.9% uptime SLA", "Max latency 200ms"],
    "payment_terms": "500 USDC/month with SLA credits"
  },
  "claim": "Uptime fell below 99.9% SLA.",
  "desired_remedy": "service_credit",
  "policy": "sla-monitoring",
  "evidence": [
    {
      "type": "contract",
      "source": "agreement.json",
      "timestamp": "2026-06-01",
      "claimed_fact": "Provider agrees to 99.9% uptime SLA"
    },
    {
      "type": "log",
      "source": "uptime_monitor",
      "timestamp": "2026-06-22",
      "claimed_fact": "Measured actual uptime of 98.2% during June monitoring period"
    },
    {
      "type": "log",
      "source": "incident_log",
      "timestamp": "2026-06-15",
      "claimed_fact": "Three outages totaling 4 hours of downtime"
    }
  ]
}
